-- Curriculum-structured version of ML CityBuilder
CREATE DATABASE IF NOT EXISTS ml_citybuilder CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE ml_citybuilder;

DROP TABLE IF EXISTS user_attempts;
DROP TABLE IF EXISTS tasks;
DROP TABLE IF EXISTS user_topic_stats;
DROP TABLE IF EXISTS user_state;
DROP TABLE IF EXISTS users;
DROP TABLE IF EXISTS activity_log;

CREATE TABLE users (
  id INT AUTO_INCREMENT PRIMARY KEY,
  username VARCHAR(50) NOT NULL UNIQUE,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE user_state (
  user_id INT PRIMARY KEY,
  revenue INT NOT NULL DEFAULT 0,
  happiness INT NOT NULL DEFAULT 50,
  xp INT NOT NULL DEFAULT 0,
  current_easy INT NOT NULL DEFAULT 1,
  current_medium INT NOT NULL DEFAULT 1,
  current_hard INT NOT NULL DEFAULT 1,
  houses INT NOT NULL DEFAULT 0,
  factories INT NOT NULL DEFAULT 0,
  parks INT NOT NULL DEFAULT 0,
  labs INT NOT NULL DEFAULT 0,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE user_topic_stats (
  user_id INT NOT NULL,
  ml_topic VARCHAR(100) NOT NULL,
  attempts INT NOT NULL DEFAULT 0,
  correct_count INT NOT NULL DEFAULT 0,
  PRIMARY KEY (user_id, ml_topic),
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE tasks (
  task_id INT AUTO_INCREMENT PRIMARY KEY,
  ml_topic VARCHAR(100) NOT NULL,
  task_type VARCHAR(20) NOT NULL DEFAULT 'mcq',
  prompt TEXT NOT NULL,
  options JSON NOT NULL,
  correct_answer JSON NOT NULL,
  context JSON NOT NULL,
  reward_points INT NOT NULL DEFAULT 50,
  difficulty VARCHAR(10) NOT NULL DEFAULT 'easy',
  order_index INT NOT NULL DEFAULT 1,
  INDEX idx_diff_order (difficulty, order_index),
  INDEX idx_topic_diff_order (ml_topic, difficulty, order_index)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE activity_log (
  id INT AUTO_INCREMENT PRIMARY KEY,
  user_id INT NOT NULL,
  event_type VARCHAR(40) NOT NULL,
  message VARCHAR(255) NOT NULL,
  meta_json JSON NULL,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  INDEX idx_user_created (user_id, created_at),
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE badges (
  id INT AUTO_INCREMENT PRIMARY KEY,
  code VARCHAR(60) NOT NULL UNIQUE,
  name VARCHAR(100) NOT NULL,
  description VARCHAR(255) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE user_badges (
  user_id INT NOT NULL,
  badge_id INT NOT NULL,
  earned_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (user_id, badge_id),
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
  FOREIGN KEY (badge_id) REFERENCES badges(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


CREATE TABLE user_attempts (
  id INT AUTO_INCREMENT PRIMARY KEY,
  user_id INT NOT NULL,
  task_id INT NOT NULL,
  ml_topic VARCHAR(100) NOT NULL,
  difficulty VARCHAR(10) NOT NULL,
  was_correct TINYINT(1) NOT NULL DEFAULT 0,
  response_seconds INT NOT NULL DEFAULT 0,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
  FOREIGN KEY (task_id) REFERENCES tasks(task_id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

