INSERT INTO badges (code, name, description) VALUES
('course_easy_complete', 'Foundations Finisher', 'Completed the full Foundations / Easy curriculum.'),
('course_medium_complete', 'Intermediate Finisher', 'Completed the full Intermediate / Medium curriculum.'),
('course_hard_complete', 'Advanced Finisher', 'Completed the full Advanced / Hard curriculum.');
INSERT INTO tasks (ml_topic, task_type, prompt, options, correct_answer, context, reward_points, difficulty, order_index) VALUES
('intro', 'mcq', 'Which statement best describes machine learning?', '["Identify patterns from data", "It means manually writing every rule by hand", "It is mainly about deleting labels", "It guarantees perfect predictions"]', '"Identify patterns from data"', '{"concept": "Machine Learning", "lesson": "Foundation lesson 1: Machine Learning. This concept helps learners understand how machine-learning systems identify patterns from data. In a smart-city context, this appears in tasks such as forecasting traffic demand. Read carefully before answering the question.", "explanation": "Machine Learning helps a learner understand how models identify patterns from data.", "city_example": "In the project, forecasting traffic demand is a useful smart-city example of machine learning.", "hint": "Focus on the core definition.", "why_it_matters": "This concept supports stronger decisions and helps learners build transferable machine-learning understanding.", "common_mistake": "Learners often confuse machine learning with a related term, so focus on its exact role."}', 50, 'easy', 1),
('supervised', 'mcq', 'A city team wants to training on labelled service requests. Which ML idea fits this best?', '["A spreadsheet colour change", "Learn from labelled examples", "A manual guess with no data", "A badge counter only"]', '"Learn from labelled examples"', '{"concept": "Supervised Learning", "lesson": "Foundation lesson 2: Supervised Learning. This concept helps learners understand how machine-learning systems learn from labelled examples. In a smart-city context, this appears in tasks such as training on labelled service requests. Read carefully before answering the question.", "explanation": "Supervised Learning helps a learner understand how models learn from labelled examples.", "city_example": "In the project, training on labelled service requests is a useful smart-city example of supervised learning.", "hint": "Match the concept to the city example.", "why_it_matters": "This concept supports stronger decisions and helps learners build transferable machine-learning understanding.", "common_mistake": "Learners often confuse supervised learning with a related term, so focus on its exact role."}', 50, 'easy', 2),
('unsupervised', 'mcq', 'Why is unsupervised learning useful in machine learning?', '["It removes the need for evaluation", "It makes every dataset unbiased automatically", "Find structure without labels", "It only matters for file storage"]', '"Find structure without labels"', '{"concept": "Unsupervised Learning", "lesson": "Foundation lesson 3: Unsupervised Learning. This concept helps learners understand how machine-learning systems find structure without labels. In a smart-city context, this appears in tasks such as grouping neighbourhoods by travel pattern. Read carefully before answering the question.", "explanation": "Unsupervised Learning helps a learner understand how models find structure without labels.", "city_example": "In the project, grouping neighbourhoods by travel pattern is a useful smart-city example of unsupervised learning.", "hint": "Think about why the concept helps learning or prediction.", "why_it_matters": "This concept supports stronger decisions and helps learners build transferable machine-learning understanding.", "common_mistake": "Learners often confuse unsupervised learning with a related term, so focus on its exact role."}', 50, 'easy', 3),
('classification', 'mcq', 'Which option is the clearest example of classification?', '["Renaming a folder", "Printing a static PDF", "Changing a chart title", "Predict categories"]', '"Predict categories"', '{"concept": "Classification", "lesson": "Foundation lesson 4: Classification. This concept helps learners understand how machine-learning systems predict categories. In a smart-city context, this appears in tasks such as predicting urgent or not urgent. Read carefully before answering the question.", "explanation": "Classification helps a learner understand how models predict categories.", "city_example": "In the project, predicting urgent or not urgent is a useful smart-city example of classification.", "hint": "Pick the option that reflects the concept itself.", "why_it_matters": "This concept supports stronger decisions and helps learners build transferable machine-learning understanding.", "common_mistake": "Learners often confuse classification with a related term, so focus on its exact role."}', 50, 'easy', 4),
('regression', 'mcq', 'If a learner understands regression, what should they know first?', '["Predict continuous numbers", "That every model must be perfect", "That data never changes", "That testing is unnecessary"]', '"Predict continuous numbers"', '{"concept": "Regression", "lesson": "Foundation lesson 5: Regression. This concept helps learners understand how machine-learning systems predict continuous numbers. In a smart-city context, this appears in tasks such as predicting daily energy demand. Read carefully before answering the question.", "explanation": "Regression helps a learner understand how models predict continuous numbers.", "city_example": "In the project, predicting daily energy demand is a useful smart-city example of regression.", "hint": "Choose the foundational statement.", "why_it_matters": "This concept supports stronger decisions and helps learners build transferable machine-learning understanding.", "common_mistake": "Learners often confuse regression with a related term, so focus on its exact role."}', 50, 'easy', 5),
('features', 'mcq', 'Which statement best describes features?', '["It means manually writing every rule by hand", "Act as inputs to a model", "It is mainly about deleting labels", "It guarantees perfect predictions"]', '"Act as inputs to a model"', '{"concept": "Features", "lesson": "Foundation lesson 6: Features. This concept helps learners understand how machine-learning systems act as inputs to a model. In a smart-city context, this appears in tasks such as using rainfall and time of day. Read carefully before answering the question.", "explanation": "Features helps a learner understand how models act as inputs to a model.", "city_example": "In the project, using rainfall and time of day is a useful smart-city example of features.", "hint": "Focus on the core definition.", "why_it_matters": "This concept supports stronger decisions and helps learners build transferable machine-learning understanding.", "common_mistake": "Learners often confuse features with a related term, so focus on its exact role."}', 50, 'easy', 6),
('labels', 'mcq', 'A city team wants to marking a road as dangerous. Which ML idea fits this best?', '["A spreadsheet colour change", "A manual guess with no data", "Act as the correct answer during training", "A badge counter only"]', '"Act as the correct answer during training"', '{"concept": "Labels", "lesson": "Foundation lesson 7: Labels. This concept helps learners understand how machine-learning systems act as the correct answer during training. In a smart-city context, this appears in tasks such as marking a road as dangerous. Read carefully before answering the question.", "explanation": "Labels helps a learner understand how models act as the correct answer during training.", "city_example": "In the project, marking a road as dangerous is a useful smart-city example of labels.", "hint": "Match the concept to the city example.", "why_it_matters": "This concept supports stronger decisions and helps learners build transferable machine-learning understanding.", "common_mistake": "Learners often confuse labels with a related term, so focus on its exact role."}', 50, 'easy', 7),
('training', 'mcq', 'Why is training useful in machine learning?', '["It removes the need for evaluation", "It makes every dataset unbiased automatically", "It only matters for file storage", "Fit a model using examples"]', '"Fit a model using examples"', '{"concept": "Training", "lesson": "Foundation lesson 8: Training. This concept helps learners understand how machine-learning systems fit a model using examples. In a smart-city context, this appears in tasks such as learning from historical bus delay data. Read carefully before answering the question.", "explanation": "Training helps a learner understand how models fit a model using examples.", "city_example": "In the project, learning from historical bus delay data is a useful smart-city example of training.", "hint": "Think about why the concept helps learning or prediction.", "why_it_matters": "This concept supports stronger decisions and helps learners build transferable machine-learning understanding.", "common_mistake": "Learners often confuse training with a related term, so focus on its exact role."}', 50, 'easy', 8),
('testing', 'mcq', 'Which option is the clearest example of testing?', '["Check performance on unseen data", "Renaming a folder", "Printing a static PDF", "Changing a chart title"]', '"Check performance on unseen data"', '{"concept": "Testing", "lesson": "Foundation lesson 9: Testing. This concept helps learners understand how machine-learning systems check performance on unseen data. In a smart-city context, this appears in tasks such as checking predictions on future traffic days. Read carefully before answering the question.", "explanation": "Testing helps a learner understand how models check performance on unseen data.", "city_example": "In the project, checking predictions on future traffic days is a useful smart-city example of testing.", "hint": "Pick the option that reflects the concept itself.", "why_it_matters": "This concept supports stronger decisions and helps learners build transferable machine-learning understanding.", "common_mistake": "Learners often confuse testing with a related term, so focus on its exact role."}', 50, 'easy', 9),
('train_test', 'mcq', 'If a learner understands a train/test split, what should they know first?', '["That every model must be perfect", "Separate learning from evaluation", "That data never changes", "That testing is unnecessary"]', '"Separate learning from evaluation"', '{"concept": "A Train/Test Split", "lesson": "Foundation lesson 10: A Train/Test Split. This concept helps learners understand how machine-learning systems separate learning from evaluation. In a smart-city context, this appears in tasks such as holding back unseen examples. Read carefully before answering the question.", "explanation": "A Train/Test Split helps a learner understand how models separate learning from evaluation.", "city_example": "In the project, holding back unseen examples is a useful smart-city example of a train/test split.", "hint": "Choose the foundational statement.", "why_it_matters": "This concept supports stronger decisions and helps learners build transferable machine-learning understanding.", "common_mistake": "Learners often confuse a train/test split with a related term, so focus on its exact role."}', 50, 'easy', 10),
('accuracy', 'mcq', 'Which statement best describes accuracy?', '["It means manually writing every rule by hand", "It is mainly about deleting labels", "Measure the proportion of correct predictions", "It guarantees perfect predictions"]', '"Measure the proportion of correct predictions"', '{"concept": "Accuracy", "lesson": "Foundation lesson 11: Accuracy. This concept helps learners understand how machine-learning systems measure the proportion of correct predictions. In a smart-city context, this appears in tasks such as counting correct service classifications. Read carefully before answering the question.", "explanation": "Accuracy helps a learner understand how models measure the proportion of correct predictions.", "city_example": "In the project, counting correct service classifications is a useful smart-city example of accuracy.", "hint": "Focus on the core definition.", "why_it_matters": "This concept supports stronger decisions and helps learners build transferable machine-learning understanding.", "common_mistake": "Learners often confuse accuracy with a related term, so focus on its exact role."}', 50, 'easy', 11),
('overfitting', 'mcq', 'A city team wants to learning old traffic quirks. Which ML idea fits this best?', '["A spreadsheet colour change", "A manual guess with no data", "A badge counter only", "Memorise training data too closely"]', '"Memorise training data too closely"', '{"concept": "Overfitting", "lesson": "Foundation lesson 12: Overfitting. This concept helps learners understand how machine-learning systems memorise training data too closely. In a smart-city context, this appears in tasks such as learning old traffic quirks. Read carefully before answering the question.", "explanation": "Overfitting helps a learner understand how models memorise training data too closely.", "city_example": "In the project, learning old traffic quirks is a useful smart-city example of overfitting.", "hint": "Match the concept to the city example.", "why_it_matters": "This concept supports stronger decisions and helps learners build transferable machine-learning understanding.", "common_mistake": "Learners often confuse overfitting with a related term, so focus on its exact role."}', 50, 'easy', 12),
('underfitting', 'mcq', 'Why is underfitting useful in machine learning?', '["Miss the pattern because the model is too simple", "It removes the need for evaluation", "It makes every dataset unbiased automatically", "It only matters for file storage"]', '"Miss the pattern because the model is too simple"', '{"concept": "Underfitting", "lesson": "Foundation lesson 13: Underfitting. This concept helps learners understand how machine-learning systems miss the pattern because the model is too simple. In a smart-city context, this appears in tasks such as using a weak demand model. Read carefully before answering the question.", "explanation": "Underfitting helps a learner understand how models miss the pattern because the model is too simple.", "city_example": "In the project, using a weak demand model is a useful smart-city example of underfitting.", "hint": "Think about why the concept helps learning or prediction.", "why_it_matters": "This concept supports stronger decisions and helps learners build transferable machine-learning understanding.", "common_mistake": "Learners often confuse underfitting with a related term, so focus on its exact role."}', 50, 'easy', 13),
('preprocessing', 'mcq', 'Which option is the clearest example of preprocessing?', '["Renaming a folder", "Prepare messy data before modelling", "Printing a static PDF", "Changing a chart title"]', '"Prepare messy data before modelling"', '{"concept": "Preprocessing", "lesson": "Foundation lesson 14: Preprocessing. This concept helps learners understand how machine-learning systems prepare messy data before modelling. In a smart-city context, this appears in tasks such as cleaning sensor data. Read carefully before answering the question.", "explanation": "Preprocessing helps a learner understand how models prepare messy data before modelling.", "city_example": "In the project, cleaning sensor data is a useful smart-city example of preprocessing.", "hint": "Pick the option that reflects the concept itself.", "why_it_matters": "This concept supports stronger decisions and helps learners build transferable machine-learning understanding.", "common_mistake": "Learners often confuse preprocessing with a related term, so focus on its exact role."}', 50, 'easy', 14),
('generalisation', 'mcq', 'If a learner understands generalisation, what should they know first?', '["That every model must be perfect", "That data never changes", "Perform well on new unseen cases", "That testing is unnecessary"]', '"Perform well on new unseen cases"', '{"concept": "Generalisation", "lesson": "Foundation lesson 15: Generalisation. This concept helps learners understand how machine-learning systems perform well on new unseen cases. In a smart-city context, this appears in tasks such as predicting tomorrow''s congestion. Read carefully before answering the question.", "explanation": "Generalisation helps a learner understand how models perform well on new unseen cases.", "city_example": "In the project, predicting tomorrow''s congestion is a useful smart-city example of generalisation.", "hint": "Choose the foundational statement.", "why_it_matters": "This concept supports stronger decisions and helps learners build transferable machine-learning understanding.", "common_mistake": "Learners often confuse generalisation with a related term, so focus on its exact role."}', 50, 'easy', 15),
